// // Asynchronous reset functionality: Q takes the value of D on the falling edge of CLK and is set to HIGH when RST is active.
module top_module(output reg Q,
   input wire D,
   input wire CLK,
   input wire RST
   );always @(posedge CLK or posedge RST)
     if (RST)
       Q <= 0;
     else
       Q <= D;

endmodule
